const SCHEMA = {"type": "object", "additionalProperties": false, "required": ["chapter", "core_intuitions", "existing", "new_figures", "summary"], "properties": {"chapter": {"type": "string"}, "core_intuitions": {"type": "array", "maxItems": 6, "items": {"type": "string"}, "description": "the handful of ideas a reader MUST grok intuitively to understand this chapter"}, "existing": {"type": "array", "maxItems": 15, "items": {"type": "object", "additionalProperties": false, "required": ["name", "verdict"], "properties": {"name": {"type": "string"}, "verdict": {"type": "string", "enum": ["keep", "refine", "replace"]}, "issue": {"type": "string", "description": "what's weak (for refine/replace)"}, "improvement": {"type": "string", "description": "concrete change to make"}}}}, "new_figures": {"type": "array", "maxItems": 5, "items": {"type": "object", "additionalProperties": false, "required": ["name", "concept", "rationale", "kind", "placement", "brief"], "properties": {"name": {"type": "string", "description": "kebab-case file stem, unique, descriptive"}, "concept": {"type": "string", "description": "one line: what it visualizes"}, "rationale": {"type": "string", "description": "why THIS is foundational for intuition here"}, "kind": {"type": "string", "enum": ["static", "animated", "long-animation"]}, "placement": {"type": "string", "description": "section heading / anchor text to place the marker after"}, "brief": {"type": "string", "description": "rich, specific drawing brief: what to show, the visual metaphor, labels, stages, what must be legible; enough for a drawer to execute without re-reading the chapter"}, "priority": {"type": "integer", "minimum": 1, "maximum": 3, "description": "1=must-have foundational, 3=nice-to-have"}}}}, "summary": {"type": "string"}}}

phase('Strategize')
const results = await parallel(CH.map(c => () =>
  agent(c.prompt, { label: `figplan:${c.id}`, phase: 'Strategize', schema: SCHEMA,
                    model: 'opus', effort: 'high' })))

const ok = results.filter(Boolean)
const died = CH.filter((c, i) => !results[i]).map(c => c.id)
let nNew = 0, nRefine = 0, nReplace = 0, nLong = 0
for (const r of ok) {
  nNew += (r.new_figures || []).length
  nLong += (r.new_figures || []).filter(f => f.kind === 'long-animation').length
  for (const e of (r.existing || [])) { if (e.verdict === 'refine') nRefine++; if (e.verdict === 'replace') nReplace++ }
}
log(`strategized ${ok.length}/${CH.length} | new=${nNew} (long-anim=${nLong}) | refine=${nRefine} | replace=${nReplace}`)
if (died.length) log(`DIED (re-run to resume): ${died.join(', ')}`)
return { strategized: ok.length, died, nNew, nLong, nRefine, nReplace }
